import * as p from "@clack/prompts";
import * as fs from "fs/promises";
import * as path from "path";
import * as os from "os";
import { Kysely, PostgresDialect, MysqlDialect, MssqlDialect } from "kysely";
import { Pool } from "pg";
import { createPool as createMysqlPool } from "mysql2";
const BIGQUERY_CREDENTIALS_FILENAME = "bigquery-service-account.json";
const BIGQUERY_CREDENTIALS_CONTAINER_PATH = `/inconvo/credentials/${BIGQUERY_CREDENTIALS_FILENAME}`;
function getBigQueryCredentialsDir() {
    return path.join(getInconvoDir(), "credentials");
}
function getBigQueryCredentialsHostPath() {
