                redshift: "postgresql://user:password@cluster.region.redshift.amazonaws.com:5439/database?sslmode=require",
                mysql: "mysql://user:password@localhost:3306/database",
                mssql: "mssql://user:password@localhost:1433/database?encrypt=true&trustServerCertificate=true",
            };
            const urlInput = await p.text({
                message: "Enter your database connection string:",
                placeholder: placeholders[databaseDialect],
                validate: (value) => {
                    if (!value)
                        return "Connection string is required";
